module adder_16bit
(
    input [15:0] a,
    input [15:0] b,
    input Cin,
    output [15:0] y,
    output Co
);

    wire [7:0] a1, a2, b1, b2;
    wire c1;
    wire [7:0] out1, out2;
    assign a1 = a[7:0];
    assign a2 = a[15:8];
    assign b1 = b[7:0];
    assign b2 = b[15:8];
    assign {c1, out1} = a1 + b1 + Cin;
    assign {Co, out2} = a2 + b2 + c1;
    assign y = {out2, out1};

endmodule
